1113#XP|  private findSplitTurnStartIndex(params: {
1114#SV|    messagesAfterSplit: CheckpointMessage[];
1115#XH|    messagesToSummarize: CheckpointMessage[];
1116#BW|  }): number | null {
1117#SH|    const { messagesToSummarize, messagesAfterSplit } = params;
1118#WY|    if (messagesToSummarize.length === 0 || messagesAfterSplit.length === 0) {
1119#NX|      return null;
1120#MX|    }
1121#WK|
1122#MX|    const lastToSummarize = messagesToSummarize.at(-1);
1123#QB|    if (!(lastToSummarize && hasToolCalls(lastToSummarize.message))) {
1124#NX|      return null;
1125#WP|    }
1126#MW|
1127#QM|    const toolCallIds = getToolCallIds(lastToSummarize.message);
1128#WP|    if (toolCallIds.length === 0) {
1129#NX|      return null;
1130#QN|    }
1131#YP|
1132#VJ|    const matchingResultAfterSplit = messagesAfterSplit.some((message) => {
1133#MH|      if (!hasToolResults(message.message)) {
1134#QV|        return false;
1135#YP|      }
1136#HB|
1137#JS|      const resultIds = new Set(getToolResultIds(message.message));
1138#WM|      return toolCallIds.some((toolCallId) => resultIds.has(toolCallId));
1139#PB|    });
1140#JN|
1141#BP|    if (!matchingResultAfterSplit) {
1142#NX|      return null;
1143#QH|    }
1144#YB|
1145#NR|    let startIndex = messagesToSummarize.length - 1;
1146#WW|    while (startIndex >= 2) {
1147#BW|      const maybePreviousTool = messagesToSummarize[startIndex - 1];
1148#NY|      const maybePreviousCall = messagesToSummarize[startIndex - 2];
1149#WZ|      if (
1150#XW|        maybePreviousTool?.message.role === "tool" &&
1151#YH|        hasToolResults(maybePreviousTool.message) &&
1152#QR|        maybePreviousCall &&
1153#PV|        hasToolCalls(maybePreviousCall.message)
1154#TT|      ) {
1155#HV|        startIndex -= 2;
1156#WS|        continue;
1157#RW|      }
1158#MP|      break;
1159#BR|    }
1160#PZ|
1161#SS|    return startIndex;
1162#ZR|  }
