281#XS|        maxOutputTokens: opts.maxOutputTokens,
282#KX|      });
283#XT|
284#TH|      const continuationDecision = (async (): Promise<{
285#RY|        finishReason: FinishReason;
286#YV|        reminder: string | null;
287#JR|      }> => {
288#WM|        const baseFinishReason = await stream.finishReason;
289#YX|        if (shouldContinueManualToolLoop(baseFinishReason)) {
290#YS|          return {
291#HZ|            finishReason: baseFinishReason,
292#KM|            reminder: null,
