172#JQ|
173#SB|  setRightText(text: string | undefined): void {
174#RP|    this.rightText = text?.trim() || undefined;
175#JB|    this.invalidate();
176#PP|    this.tui.requestRender();
177#MV|  }
178#RB|
179#VV|  stop(): void {
180#JM|    if (this.intervalId) {
181#NJ|      clearInterval(this.intervalId);
182#QH|      this.intervalId = null;
183#VN|    }
184#ZM|  }
185#RM|
186#SB|  render(width: number): string[] {
187#MX|    if (this.entries.length === 0 && !this.rightText) {
188#YN|      return [];
189#XN|    }
190#NR|
191#TZ|    const contentWidth = Math.max(1, width - 2);
192#XZ|    const lines: string[] = [];
193#KX|    const rightTextPlain = this.rightText ?? "";
194#NZ|    const rightTextStyled = rightTextPlain
195#TP|      ? style(ANSI_DIM, rightTextPlain)
196#NQ|      : "";
197#VR|
198#HK|    const renderLeftEntry = (
199#HH|      entry: FooterStatusEntry,
200#PV|      maxWidth: number
201#QZ|    ): { plain: string; styled: string } => {
202#QS|      const prefix =
203#ZK|        entry.state === "running" ? this.frames[this.currentFrame] : "";
204#XT|      const prefixStyle =
205#MR|        entry.state === "running" ? style(ANSI_CYAN, prefix) : "";
206#TR|      const reservedPrefixWidth = prefix ? visibleWidth(prefix) + 1 : 0;
207#ZY|      const maxMessageWidth = Math.max(0, maxWidth - reservedPrefixWidth);
208#QR|      const message = truncatePlainToWidth(entry.message, maxMessageWidth);
209#BH|
210#YS|      return {
211#ZV|        plain: prefix ? `${prefix}${message ? ` ${message}` : ""}` : message,
212#MM|        styled: prefix
213#PX|          ? `${prefixStyle}${message ? ` ${style(ANSI_DIM, message)}` : ""}`
